import{_ as e,c as t,o as p,d as o}from"./app.4c449db1.js";const g='{"title":"\u0423\u0441\u0442\u0430\u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0432\u0435\u043B\u043E\u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","description":"","frontmatter":{"title":"\u0423\u0441\u0442\u0430\u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0432\u0435\u043B\u043E\u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","date":"2015-05-28","cover":"cibwruhs20eo26tvuj9xk8q6cd9hyl-org.jpg"},"headers":[{"level":3,"title":"\u0423\u0441\u0442\u0430\u0432 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438 \xAB\u0413\u0430\u0440\u0430\u0436 38\xBB","slug":"\u0443\u0441\u0442\u0430\u0432-\u0432\u0435n\u043E\u043A\u0443\u0445\u043D\u0438-\xAB\u0433\u0430\u0440\u0430\u0436-38\xBB"}],"relativePath":"theory/research/ustav-garazh-38/index.md"}',a={},r=o('<p>\u041F\u043E\u0434\u0440\u043E\u0431\u043D\u044B\u0439 \u0438 \u043F\u0440\u043E\u0434\u0443\u043C\u0430\u043D\u043D\u044B\u0439 \u0443\u0441\u0442\u0430\u0432 \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0449\u0435\u0439 \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0439\xA0\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u041F\u043E\u043B\u0435\u0437\u043D\u044B\u0435 \u043D\u0430\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0411\u0435\u043B\u043E\u0440\u0443\u0441\u0441\u043A\u0438\u0445 \u043A\u043E\u043B\u043B\u0435\u0433 (\u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0441 \u043A\u043E\u0440\u0440\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u043A\u043E\u0439).</p><blockquote><p><a href="/workshop/catalog/velokuhnya-garazh-38/"><strong>\u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F &quot;\u0413\u0430\u0440\u0430\u0436 38&quot;</strong></a> \u2014 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u0430\u044F \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0432\u0435\u043B\u043E\u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u0433\u043E\u0440\u043E\u0434\u0430, \u043C\u0435\u0441\u0442\u043E \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439 \u043D\u0430 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u0443\u044E \u0442\u0435\u043C\u0430\u0442\u0438\u043A\u0443. \u041F\u043E \u0432\u0441\u0435\u043C\u0443 \u043C\u0438\u0440\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043C\u043D\u043E\u0433\u043E \u0442\u0430\u043A\u0438\u0445 \u043C\u0435\u0441\u0442, \u0438 \u0432\u0435\u0437\u0434\u0435 \u043E\u043D\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F\xA0\u0446\u0435\u043D\u0442\u0440\u0430\u043C\u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0439 \u0436\u0438\u0437\u043D\u0438, \u0441\u043E\u0431\u0438\u0440\u0430\u044E\u0449\u0438\u043C\u0438\xA0\u0432\u043E\u043A\u0440\u0443\u0433 \u0441\u0435\u0431\u044F \u0441\u0430\u043C\u044B\u0445 \u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0445 \u043B\u044E\u0434\u0435\u0439.</p></blockquote><h3 id="\u0443\u0441\u0442\u0430\u0432-\u0432\u0435n\u043E\u043A\u0443\u0445\u043D\u0438-\xAB\u0433\u0430\u0440\u0430\u0436-38\xBB" tabindex="-1">\u0423\u0441\u0442\u0430\u0432 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438 \xAB\u0413\u0430\u0440\u0430\u0436 38\xBB <a class="header-anchor" href="#\u0443\u0441\u0442\u0430\u0432-\u0432\u0435n\u043E\u043A\u0443\u0445\u043D\u0438-\xAB\u0433\u0430\u0440\u0430\u0436-38\xBB" aria-hidden="true">#</a></h3><p><em>\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D \u041F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435\u043C &quot;\u041C\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430&quot; 12.08.2013 \u0433.</em></p><p>\u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F \xAB\u0413\u0430\u0440\u0430\u0436 38\xBB - \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u0430\u044F \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F.</p><p>\u0420\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u0443\u0435\u043C\u0441\u044F \u043E\u043F\u044B\u0442\u043E\u043C \u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0439 \u043C\u0438\u0440\u043E\u0432\u043E\u0433\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F BikeKitchen, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u0442\u0440\u0435\u043C\u0438\u043C\u0441\u044F \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043E\u0431\u0440\u0430\u0437.</p><p>\u041B\u044E\u0431\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u0439\u0442\u0438 \u0432 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044E \u0438 \u0432\u043E\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u043C\u0438 \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043C\u0438 \u0434\u043B\u044F \u0440\u0435\u043C\u043E\u043D\u0442\u0430, \u043E\u0431\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0430 \u0438\u043B\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0447\u0435\u0433\u043E-\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u0441 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0439 \u0442\u0435\u043C\u0430\u0442\u0438\u043A\u043E\u0439.</p><p>\u0415\u0441\u043B\u0438 \u0432\u044B \u0447\u0442\u043E-\u0442\u043E \u0432\u0437\u044F\u043B\u0438 \u0432\xA0\u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0435, \u043E\u0441\u0442\u0430\u0432\u044C\u0442\u0435, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430, \u0447\u0442\u043E-\u0442\u043E \u0432\u0437\u0430\u043C\u0435\u043D: \u044D\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 \u0432 \u0434\u0435\u043D\u0435\u0436\u043D\u043E\u0439 \u0438\u043B\u0438 \u043D\u0430\u0442\u0443\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043F\u043E\u043C\u043E\u0449\u044C \u0432 \u043E\u0431\u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438, \u043F\u043E\u043C\u043E\u0449\u044C \u0434\u0440\u0443\u0433\u0438\u043C \u043F\u043E\u0441\u0435\u0442\u0438\u0442\u0435\u043B\u044F\u043C. \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0437\u0430 \u0441\u0447\u0435\u0442 \u043F\u043E\u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0439 \u0438 \u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u043E\u0439 \u043F\u043E\u043C\u043E\u0449\u0438.</p><p>\u041F\u043E\u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 \u0437\u0430\u043F\u0447\u0430\u0441\u0442\u0435\u0439, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0440\u0430\u0441\u0445\u043E\u0434\u043D\u044B\u0445 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044F, \u043D\u043E \u043E\u043D\u0438 \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u0432 \u043F\u0440\u0438\u0433\u043E\u0434\u043D\u043E\u043C \u0434\u043B\u044F \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438.</p><p>\u0414\u0435\u043D\u0435\u0436\u043D\u044B\u0435 \u043F\u043E\u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0434\u043B\u044F \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0435\u0440\u0435\u0447\u0438\u0441\u043B\u044F\u0442\u044C \u043D\u0430 \u0431\u0430\u043D\u043A\u043E\u0432\u0441\u043A\u0438\u0439 \u0441\u0447\u0435\u0442 \u041C\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430.</p><p>\u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F - \u044D\u0442\u043E \u043D\u0435 \u043C\u0430\u0433\u0430\u0437\u0438\u043D. \u041F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430, \u043D\u0435 \u0432\u044B\u043D\u043E\u0441\u0438\u0442\u0435 \u0438\u0437 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043D\u0438\u0447\u0435\u0433\u043E, \u043A\u0440\u043E\u043C\u0435 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u043D\u0430 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434 \u0437\u0430\u043F\u0447\u0430\u0441\u0442\u0435\u0439.</p><p>\u0412 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043D\u0435 \u0434\u043E\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0446\u0435\u043B\u044F\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u0412 \u0447\u0430\u0441\u0442\u043D\u043E\u0441\u0442\u0438, \u0437\u0430\u043F\u0440\u0435\u0449\u0430\u044E\u0442\u0441\u044F: \u043F\u0440\u043E\u0434\u0430\u0436\u0430 \u0443\u0441\u043B\u0443\u0433 \u0438 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432, \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0438\u043B\u0438 \u043F\u043E\u043A\u0430\u0437 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u043F\u043E\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0430. \u0420\u0430\u0437\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E, \u043B\u0438\u0447\u043D\u043E\u0433\u043E \u0438 \u0441\u043F\u043E\u0440\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0430 \u0440\u0430\u0437\u0440\u0435\u0448\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u043E\u0442\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0445 \u043C\u0435\u0441\u0442\u0430\u0445.</p><p>\u041D\u0435 \u0434\u043E\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0430\u0442 \u0437\u0430\u043A\u043E\u043D\u043E\u0434\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0443 \u0420\u0435\u0441\u043F\u0443\u0431\u043B\u0438\u043A\u0438 \u0411\u0435\u043B\u0430\u0440\u0443\u0441\u044C.</p><p><strong>\u041A\u0443\u0440\u0430\u0442\u043E\u0440</strong> \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438 \u2013 \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u043A, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0438 \u0441\u043B\u0435\u0434\u0438\u0442 \u0437\u0430 \u043F\u043E\u0440\u044F\u0434\u043A\u043E\u043C.</p><p>\u041A\u0443\u0440\u0430\u0442\u043E\u0440 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0438\u0437\u0431\u0440\u0430\u043D \u0442\u0440\u0435\u0442\u044C\u044E \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u043E\u0432. \u041A\u0443\u0440\u0430\u0442\u043E\u0440 \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D \u043F\u0440\u0435\u0434\u0441\u0435\u0434\u0430\u0442\u0435\u043B\u0435\u043C \u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0426\u0420\u0422.</p><p>\u041F\u043E\u0441\u0435\u0442\u0438\u0442\u0435\u043B\u0438 \u043C\u043E\u0433\u0443\u0442 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u0432 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0438 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u0430.</p><p>\u041E\u043F\u0435\u0440\u0430\u0442\u0438\u0432\u043D\u044B\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E\u043C \u0433\u043E\u043B\u043E\u0441\u043E\u0432 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u043E\u0432, \u043A\u0432\u043E\u0440\u0443\u043C \u2013 \u0442\u0440\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430.</p><p>\u0418\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0438 \u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0423\u0441\u0442\u0430\u0432\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u041F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u041C\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0432 \u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0435\u0441\u043B\u0438 \u0441 \u043D\u0438\u043C\u0438 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B \u0431\u043E\u043B\u0435\u0435 50% \u043E\u0442 \u043E\u0431\u0449\u0435\u0433\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0447\u043B\u0435\u043D\u043E\u0432 \u041F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F.</p>',18),n=[r];function s(c,_,i,d,h,l){return p(),t("div",null,n)}var f=e(a,[["render",s]]);export{g as __pageData,f as default};
